import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';

const rootElement = document.getElementById('root');
if (!rootElement) {
  throw new Error("Could not find root element to mount to");
}

const root = ReactDOM.createRoot(rootElement);
root.render(
  <React.StrictMode>
    <App />
  </React.StrictMode>
);

export enum ToolType {
  BRUSH = 'BRUSH',
  ERASER = 'ERASER',
  MOVE = 'MOVE'
}

export interface Point {
  x: number;
  y: number;
}

export interface AppState {
  image: HTMLImageElement | null;
  imageBase64: string | null;
  isProcessing: boolean;
  generatedImage: string | null;
  brushSize: number;
  tool: ToolType;
  prompt: string;
  history: string[]; // store generated image history URLs
}

export interface ProcessingError {
  message: string;
  code?: string;
}

import { GoogleGenAI } from "@google/genai";

// Initialize Gemini Client
// In a real production app, you might proxy this through a backend to keep the key secret,
// but for this client-side demo we use the env var directly as per instructions.
const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

export const generateEditedImage = async (
  imageBase64: string,
  prompt: string
): Promise<string> => {
  try {
    // Clean base64 string if it has the prefix
    const cleanBase64 = imageBase64.replace(/^data:image\/(png|jpeg|jpg|webp);base64,/, '');

    // We use the high-quality image preview model for professional results
    const model = 'gemini-3-pro-image-preview';

    // Construct a professional system-like prompt to ensure constraints are met
    const fullPrompt = `
    ROLE: Precision Interior Architecture Editor.
    TASK: ${prompt}

    STRICT CONSTRAINTS:
    1. Modify ONLY the requested elements described in the task.
    2. Preserve original lighting, shadows, perspective, and camera angle perfectly.
    3. Do NOT introduce new objects unless explicitly requested.
    4. Maintain photorealism and architect-grade accuracy.
    5. Ensure seamless blending of edited areas with the existing environment.
    `;

    const response = await ai.models.generateContent({
      model: model,
      contents: {
        parts: [
          {
            text: fullPrompt,
          },
          {
            inlineData: {
              mimeType: 'image/png',
              data: cleanBase64,
            },
          },
        ],
      },
      config: {
        // High quality generation config
        imageConfig: {
            imageSize: '1K', // We ask for standard high quality
            aspectRatio: '1:1' // The model will generally respect the input aspect ratio roughly or we crop. 
            // Note: For editing, the model usually tries to match input. 
            // If strictly needed, we could detect aspect ratio, but 1:1 is a safe default for the config object if required.
        }
      }
    });

    // Extract image from response
    // The response candidates content parts will contain the image
    const parts = response.candidates?.[0]?.content?.parts;

    if (!parts) {
      throw new Error("No content generated");
    }

    // Find the image part
    const imagePart = parts.find(p => p.inlineData);

    if (imagePart && imagePart.inlineData && imagePart.inlineData.data) {
       return `data:image/png;base64,${imagePart.inlineData.data}`;
    }

    throw new Error("No image data found in response");

  } catch (error) {
    console.error("Gemini API Error:", error);
    throw error;
  }
};

import React from 'react';

interface ButtonProps extends React.ButtonHTMLAttributes<HTMLButtonElement> {
  variant?: 'primary' | 'secondary' | 'danger' | 'ghost';
  isLoading?: boolean;
  icon?: React.ReactNode;
}

export const Button: React.FC<ButtonProps> = ({ 
  children, 
  variant = 'primary', 
  isLoading, 
  icon,
  className = '',
  disabled,
  ...props 
}) => {
  const baseStyle = "flex items-center justify-center gap-2 px-4 py-2 rounded-lg font-medium transition-all duration-200 disabled:opacity-50 disabled:cursor-not-allowed focus:outline-none focus:ring-2 focus:ring-offset-2 focus:ring-offset-gray-900";

  const variants = {
    primary: "bg-brand-accent hover:bg-brand-accentHover text-white focus:ring-brand-accent",
    secondary: "bg-brand-700 hover:bg-brand-600 text-gray-100 focus:ring-brand-600",
    danger: "bg-red-600 hover:bg-red-700 text-white focus:ring-red-500",
    ghost: "bg-transparent hover:bg-brand-800 text-gray-300 hover:text-white"
  };

  return (
    <button 
      className={`${baseStyle} ${variants[variant]} ${className}`}
      disabled={disabled || isLoading}
      {...props}
    >
      {isLoading ? (
        <>
          <svg className="animate-spin -ml-1 mr-2 h-4 w-4 text-current" xmlns="http://www.w3.org/2000/svg" fill="none" viewBox="0 0 24 24">
            <circle className="opacity-25" cx="12" cy="12" r="10" stroke="currentColor" strokeWidth="4"></circle>
            <path className="opacity-75" fill="currentColor" d="M4 12a8 8 0 018-8V0C5.373 0 0 5.373 0 12h4zm2 5.291A7.962 7.962 0 014 12H0c0 3.042 1.135 5.824 3 7.938l3-2.647z"></path>
          </svg>
          Processing...
        </>
      ) : (
        <>
          {icon}
          {children}
        </>
      )}
