import React, { useRef, useEffect, useState, useCallback } from 'react';
import { ToolType, Point } from '../types';

interface ImageEditorProps {
  image: HTMLImageElement | null;
  tool: ToolType;
  brushSize: number;
  onMaskChange: (hasMask: boolean) => void;
}

export const ImageEditor: React.FC<ImageEditorProps> = ({ 
  image, 
  tool, 
  brushSize,
  onMaskChange 
}) => {
  const containerRef = useRef<HTMLDivElement>(null);
  const imageCanvasRef = useRef<HTMLCanvasElement>(null);
  const maskCanvasRef = useRef<HTMLCanvasElement>(null);
  const cursorRef = useRef<HTMLDivElement>(null);

  const [scale, setScale] = useState(1);
  const [isDrawing, setIsDrawing] = useState(false);
  const [lastPoint, setLastPoint] = useState<Point | null>(null);

  // Initialize and resize canvases
  useEffect(() => {
    if (!image || !containerRef.current || !imageCanvasRef.current || !maskCanvasRef.current) return;

    const container = containerRef.current;
    const imageCanvas = imageCanvasRef.current;
    const maskCanvas = maskCanvasRef.current;

    // Calculate aspect ratio fit
    const maxWidth = container.clientWidth;
    const maxHeight = container.clientHeight;
    const imgRatio = image.width / image.height;
    const containerRatio = maxWidth / maxHeight;

    let displayWidth, displayHeight;

    if (containerRatio > imgRatio) {
      displayHeight = maxHeight;
      displayWidth = displayHeight * imgRatio;
    } else {
      displayWidth = maxWidth;
      displayHeight = displayWidth / imgRatio;
    }

    // Set canvas dimensions to match display size for crisp rendering
    // Ideally we match natural size but for performance/display we scale
    // Let's use natural size for the buffer, style width for display
    imageCanvas.width = image.width;
    imageCanvas.height = image.height;
    maskCanvas.width = image.width;
    maskCanvas.height = image.height;

    // Draw the main image
    const ctx = imageCanvas.getContext('2d');
    if (ctx) {
      ctx.drawImage(image, 0, 0);
    }

    // Set CSS dimensions
    setScale(displayWidth / image.width);

  }, [image]);

  // Handle Drawing Logic
  const getCoordinates = (e: React.MouseEvent<HTMLCanvasElement>): Point | null => {
    if (!maskCanvasRef.current || !image) return null;
    const rect = maskCanvasRef.current.getBoundingClientRect();
    const x = (e.clientX - rect.left) / scale;
    const y = (e.clientY - rect.top) / scale;
    return { x, y };
  };

  const draw = useCallback((e: React.MouseEvent<HTMLCanvasElement>) => {
    if (!isDrawing || !maskCanvasRef.current) return;

    const point = getCoordinates(e);
    if (!point) return;

    const ctx = maskCanvasRef.current.getContext('2d');
    if (!ctx) return;

    ctx.lineJoin = 'round';
    ctx.lineCap = 'round';
    ctx.lineWidth = brushSize / scale; // Adjust brush size for scale

    if (tool === ToolType.ERASER) {
      ctx.globalCompositeOperation = 'destination-out';
    } else {
      ctx.globalCompositeOperation = 'source-over';
      ctx.strokeStyle = 'rgba(255, 50, 50, 0.5)'; // Red semi-transparent mask
      ctx.fillStyle = 'rgba(255, 50, 50, 0.5)';
    }

    ctx.beginPath();
    if (lastPoint) {
      ctx.moveTo(lastPoint.x, lastPoint.y);
      ctx.lineTo(point.x, point.y);
      ctx.stroke();
    } else {
        // Dot
        ctx.arc(point.x, point.y, ctx.lineWidth / 2, 0, Math.PI * 2);
        ctx.fill();
    }

    setLastPoint(point);
    onMaskChange(true); // Signal that mask has been modified
  }, [isDrawing, lastPoint, tool, brushSize, scale, onMaskChange]);

  const handleMouseDown = (e: React.MouseEvent<HTMLCanvasElement>) => {
    if (tool === ToolType.MOVE) return;
    setIsDrawing(true);
    const point = getCoordinates(e);
    setLastPoint(point);
    draw(e); // Draw initial dot
  };

  const handleMouseUp = () => {
    setIsDrawing(false);
    setLastPoint(null);
  };

  const handleMouseEnter = () => {
    if (cursorRef.current) cursorRef.current.style.display = 'block';
  };

  const handleMouseLeave = () => {
    if (cursorRef.current) cursorRef.current.style.display = 'none';
    setIsDrawing(false);
    setLastPoint(null);
  };

  // Custom Cursor for Brush Size
  const handleMouseMove = (e: React.MouseEvent<HTMLCanvasElement>) => {
      if (cursorRef.current) {
          cursorRef.current.style.left = `${e.clientX}px`;
          cursorRef.current.style.top = `${e.clientY}px`;
          cursorRef.current.style.width = `${brushSize}px`;
          cursorRef.current.style.height = `${brushSize}px`;
          cursorRef.current.style.borderColor = tool === ToolType.ERASER ? 'white' : 'red';
      }
      draw(e);
  };

  if (!image) {
    return (
      <div className="flex items-center justify-center h-full text-gray-400 border-2 border-dashed border-gray-700 rounded-xl bg-brand-800/50">
        <div className="text-center p-8">
          <p className="text-xl mb-2">Drag and drop an interior photo</p>
          <p className="text-sm text-gray-500">or upload from the sidebar</p>
        </div>
      </div>
    );
  }

  return (
    <div ref={containerRef} className="relative w-full h-full flex items-center justify-center overflow-hidden bg-brand-900 rounded-xl shadow-inner border border-brand-700">
      <div 
        className="relative shadow-2xl"
        style={{ 
          width: image.width * scale, 
          height: image.height * scale 
        }}
      >
        <canvas
          ref={imageCanvasRef}
          className="absolute top-0 left-0 w-full h-full object-contain"
        />
        <canvas
          ref={maskCanvasRef}
          className={`absolute top-0 left-0 w-full h-full object-contain ${tool === ToolType.MOVE ? 'cursor-grab' : 'cursor-none'}`}
          onMouseDown={handleMouseDown}
          onMouseMove={handleMouseMove}
          onMouseUp={handleMouseUp}
          onMouseLeave={handleMouseLeave}
          onMouseEnter={handleMouseEnter}
        />
      </div>

      {/* Custom Brush Cursor */}
      <div 
        ref={cursorRef}
        className="pointer-events-none fixed border-2 rounded-full transform -translate-x-1/2 -translate-y-1/2 z-50 mix-blend-difference"
        style={{ display: 'none' }}
      />
    </div>
  );
};

import React, { useState, useCallback, useRef } from 'react';
import { Upload, Eraser, Brush, Hand, Download, Sparkles, RefreshCcw, Layers, Zap } from 'lucide-react';
import { ImageEditor } from './components/ImageEditor';
import { Button } from './components/Button';
import { ToolType } from './types';
import { generateEditedImage } from './services/geminiService';

const EXAMPLE_PROMPTS = [
  "Change the wooden floor to polished concrete.",
  "Replace the curtains with modern roller blinds.",
  "Change the wall color to sage green with a matte finish."
];

export default function App() {
  const [image, setImage] = useState<HTMLImageElement | null>(null);
  const [imageBase64, setImageBase64] = useState<string | null>(null);
  const [generatedImage, setGeneratedImage] = useState<string | null>(null);
  const [isProcessing, setIsProcessing] = useState(false);
  const [prompt, setPrompt] = useState("");
  const [tool, setTool] = useState<ToolType>(ToolType.BRUSH);
  const [brushSize, setBrushSize] = useState(30);
  const [hasMask, setHasMask] = useState(false);
  const [error, setError] = useState<string | null>(null);

  const fileInputRef = useRef<HTMLInputElement>(null);

  const handleFileUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      const reader = new FileReader();
      reader.onload = (event) => {
        const img = new Image();
        img.onload = () => {
          setImage(img);
          setImageBase64(event.target?.result as string);
          setGeneratedImage(null);
          setHasMask(false);
          setError(null);
        };
        img.src = event.target?.result as string;
      };
      reader.readAsDataURL(file);
    }
  };

  const handleGenerate = async () => {
    if (!imageBase64 || !prompt.trim()) return;

    setIsProcessing(true);
    setError(null);

    try {
      // In a real masked implementation we would composite the mask or send it.
      // For this demo with standard Gemini 3 Pro Vision, we rely on the prompt + visual context.
      // We append mask instruction if user drew a mask (conceptually).
      let finalPrompt = prompt;
      if (hasMask) {
        finalPrompt += " (Focus purely on the indicated/masked regions if applicable, otherwise follow natural language instruction for the specific objects mentioned).";
      }

      const resultBase64 = await generateEditedImage(imageBase64, finalPrompt);
      setGeneratedImage(resultBase64);
    } catch (err: any) {
      setError(err.message || "Failed to generate image. Please try again.");
    } finally {
      setIsProcessing(false);
    }
  };

  const handleDownload = () => {
    if (generatedImage) {
      const link = document.createElement('a');
      link.href = generatedImage;
      link.download = `lumina-edit-${Date.now()}.png`;
      document.body.appendChild(link);
      link.click();
      document.body.removeChild(link);
    }
  };

  return (
    <div className="flex h-screen w-full flex-col bg-brand-900 text-gray-100 overflow-hidden font-sans">
      {/* Header */}
      <header className="flex h-16 items-center justify-between border-b border-brand-700 bg-brand-800/80 px-6 backdrop-blur-sm z-10">
        <div className="flex items-center gap-3">
          <div className="flex h-8 w-8 items-center justify-center rounded-lg bg-gradient-to-br from-brand-accent to-blue-600 shadow-lg shadow-brand-accent/20">
            <Sparkles className="h-5 w-5 text-white" />
          </div>
          <span className="text-xl font-bold tracking-tight text-white">Lumina<span className="text-brand-accent">Architect</span></span>
        </div>
        <div className="flex items-center gap-4">
           {process.env.API_KEY ? (
             <span className="text-xs font-medium text-green-400 bg-green-400/10 px-2 py-1 rounded-full border border-green-400/20">System Online</span>
           ) : (
             <span className="text-xs font-medium text-red-400 bg-red-400/10 px-2 py-1 rounded-full border border-red-400/20">API Key Missing</span>
           )}
        </div>
      </header>

      <main className="flex flex-1 overflow-hidden">
        {/* Left Toolbar */}
        <div className="flex w-16 flex-col items-center gap-4 border-r border-brand-700 bg-brand-800 py-6">
          <div className="space-y-4">
             <button 
                onClick={() => setTool(ToolType.BRUSH)}
                className={`p-3 rounded-xl transition-all ${tool === ToolType.BRUSH ? 'bg-brand-accent text-white shadow-lg shadow-brand-accent/20' : 'text-gray-400 hover:text-white hover:bg-brand-700'}`}
                title="Mask Brush"
             >
                <Brush size={20} />
             </button>
             <button 
                onClick={() => setTool(ToolType.ERASER)}
                className={`p-3 rounded-xl transition-all ${tool === ToolType.ERASER ? 'bg-brand-accent text-white shadow-lg shadow-brand-accent/20' : 'text-gray-400 hover:text-white hover:bg-brand-700'}`}
                title="Eraser"
             >
                <Eraser size={20} />
             </button>
             <button 
                onClick={() => setTool(ToolType.MOVE)}
                className={`p-3 rounded-xl transition-all ${tool === ToolType.MOVE ? 'bg-brand-accent text-white shadow-lg shadow-brand-accent/20' : 'text-gray-400 hover:text-white hover:bg-brand-700'}`}
                title="Pan/View"
             >
                <Hand size={20} />
             </button>
          </div>

          <div className="mt-auto flex flex-col items-center gap-4 border-t border-brand-700 pt-6">
             <div className="h-24 w-1 bg-brand-700 rounded-full relative group">
                <div 
                    className="absolute bottom-0 w-full bg-brand-accent rounded-full" 
                    style={{ height: `${(brushSize / 100) * 100}%` }}
                />
                <input 
                    type="range" 
                    min="5" 
                    max="100" 
                    value={brushSize} 
                    onChange={(e) => setBrushSize(Number(e.target.value))}
                    className="absolute inset-0 w-full h-full opacity-0 cursor-pointer"
                    title="Brush Size"
                />
             </div>
          </div>
        </div>

        {/* Center Canvas Area */}
        <div className="relative flex flex-1 flex-col bg-brand-900 p-8">
           <div className="flex-1 rounded-2xl border border-brand-700 bg-[url('https://www.transparenttextures.com/patterns/dark-matter.png')] shadow-2xl relative overflow-hidden">
             {generatedImage ? (
                <div className="relative w-full h-full flex items-center justify-center">
                    <img src={generatedImage} alt="Generated" className="max-w-full max-h-full object-contain shadow-2xl" />
                    <div className="absolute top-4 right-4 flex gap-2">
                        <Button variant="secondary" onClick={() => setGeneratedImage(null)} icon={<RefreshCcw size={16} />}>Original</Button>
                        <Button variant="primary" onClick={handleDownload} icon={<Download size={16} />}>Download</Button>
                    </div>
                </div>
             ) : (
                <ImageEditor 
                    image={image} 
                    tool={tool} 
                    brushSize={brushSize}
                    onMaskChange={setHasMask}
                />
             )}
           </div>

           {/* Upload Overlay if no image */}
           {!image && (
                <div className="absolute inset-0 flex items-center justify-center pointer-events-none">
                    <div className="pointer-events-auto text-center">
                        <input 
                            type="file" 
                            ref={fileInputRef}
                            className="hidden" 
                            accept="image/*"
                            onChange={handleFileUpload}
                        />
                        <Button 
                            variant="primary" 
                            className="px-8 py-4 text-lg shadow-xl shadow-brand-accent/20"
                            onClick={() => fileInputRef.current?.click()}
                            icon={<Upload size={24} />}
                        >
                            Upload Interior Photo
                        </Button>
                    </div>
                </div>
           )}
        </div>

        {/* Right Control Panel */}
        <div className="w-96 border-l border-brand-700 bg-brand-800 p-6 flex flex-col gap-6 overflow-y-auto">

            {/* Context/Instructions */}
            <div>
                <h2 className="text-lg font-semibold text-white mb-1">Edit Instructions</h2>
                <p className="text-sm text-gray-400">Describe the changes you want to see. Be specific about materials, colors, and textures.</p>
            </div>

            {/* Prompt Input */}
            <div className="flex-1 flex flex-col gap-4">
                <textarea 
                    className="w-full h-40 rounded-xl bg-brand-900 border-brand-600 p-4 text-gray-200 placeholder-gray-500 focus:border-brand-accent focus:ring-1 focus:ring-brand-accent resize-none transition-all"
                    placeholder="E.g., Change the carpet to a beige wool texture. Keep the borders dark."
                    value={prompt}
                    onChange={(e) => setPrompt(e.target.value)}
                />

                <div className="space-y-2">
                    <p className="text-xs font-medium text-gray-500 uppercase tracking-wider">Examples</p>
                    <div className="flex flex-col gap-2">
                        {EXAMPLE_PROMPTS.map((p, i) => (
                            <button 
                                key={i}
                                onClick={() => setPrompt(p)}
                                className="text-left text-xs text-gray-400 hover:text-brand-accent transition-colors p-2 rounded-lg hover:bg-brand-700/50 border border-transparent hover:border-brand-700 truncate"
                            >
                                {p}
                            </button>
                        ))}
                    </div>
                </div>
            </div>

            {/* Settings / Features */}
            <div className="space-y-4 border-t border-brand-700 pt-6">
                <div className="flex items-center justify-between text-sm">
                    <div className="flex items-center gap-2 text-gray-300">
                        <Layers size={16} />
                        <span>Preserve Geometry</span>
                    </div>
                    <div className="h-4 w-8 rounded-full bg-brand-accent/20 border border-brand-accent/40 flex items-center justify-end px-1">
                        <div className="h-2 w-2 rounded-full bg-brand-accent shadow-[0_0_8px_rgba(56,189,248,0.8)]"></div>
                    </div>
                </div>
                <div className="flex items-center justify-between text-sm">
                    <div className="flex items-center gap-2 text-gray-300">
                        <Zap size={16} />
                        <span>High Precision Mode</span>
                    </div>
                     <div className="h-4 w-8 rounded-full bg-brand-accent/20 border border-brand-accent/40 flex items-center justify-end px-1">
                        <div className="h-2 w-2 rounded-full bg-brand-accent shadow-[0_0_8px_rgba(56,189,248,0.8)]"></div>
                    </div>
                </div>
            </div>

            {error && (
                <div className="p-4 rounded-lg bg-red-900/20 border border-red-500/50 text-red-200 text-sm">
                    {error}
                </div>
            )}

            {/* Action Button */}
            <div className="mt-auto pt-6">
                <Button 
                    variant="primary" 
                    className="w-full py-4 text-lg font-semibold shadow-lg shadow-brand-accent/20 hover:shadow-brand-accent/40"
                    onClick={handleGenerate}
                    disabled={!image || !prompt}
                    isLoading={isProcessing}
                    icon={<Sparkles size={20} />}
                >
                    Generate Edit
                </Button>
                <p className="text-center text-xs text-gray-500 mt-3">
                    Powered by Gemini 3 Pro Vision
                </p>
            </div>
        </div>
      </main>
    </div>
  );
}

export enum ToolType {
  BRUSH = 'BRUSH',
  ERASER = 'ERASER',
  MOVE = 'MOVE'
}

export enum EditMode {
  EDIT = 'EDIT',
  REMOVE = 'REMOVE'
}

export interface Point {
  x: number;
  y: number;
}

export interface AppState {
  image: HTMLImageElement | null;
  imageBase64: string | null;
  isProcessing: boolean;
  generatedImage: string | null;
  brushSize: number;
  tool: ToolType;
  prompt: string;
  history: string[]; // store generated image history URLs
}

export interface ProcessingError {
  message: string;
  code?: string;
}

export interface ImageEditorHandle {
  getMaskDataURL: () => string | null;
}

import React, { useRef, useEffect, useState, useCallback, useImperativeHandle, forwardRef } from 'react';
import { ToolType, Point, ImageEditorHandle } from '../types';

interface ImageEditorProps {
  image: HTMLImageElement | null;
  tool: ToolType;
  brushSize: number;
  onMaskChange: (hasMask: boolean) => void;
}

export const ImageEditor = forwardRef<ImageEditorHandle, ImageEditorProps>(({ 
  image, 
  tool, 
  brushSize,
  onMaskChange 
}, ref) => {
  const containerRef = useRef<HTMLDivElement>(null);
  const imageCanvasRef = useRef<HTMLCanvasElement>(null);
  const maskCanvasRef = useRef<HTMLCanvasElement>(null);
  const cursorRef = useRef<HTMLDivElement>(null);

  const [scale, setScale] = useState(1);
  const [isDrawing, setIsDrawing] = useState(false);
  const [lastPoint, setLastPoint] = useState<Point | null>(null);

  // Expose methods to parent
  useImperativeHandle(ref, () => ({
    getMaskDataURL: () => {
      if (!maskCanvasRef.current || !image) return null;

      const width = maskCanvasRef.current.width;
      const height = maskCanvasRef.current.height;
      const ctx = maskCanvasRef.current.getContext('2d');

      if (!ctx) return null;

      // Get the current mask data (red strokes)
      const imgData = ctx.getImageData(0, 0, width, height);
      const data = imgData.data;

      // Create a temporary canvas to generate the binary mask
      const tempCanvas = document.createElement('canvas');
      tempCanvas.width = width;
      tempCanvas.height = height;
      const tempCtx = tempCanvas.getContext('2d');

      if (!tempCtx) return null;

      // Create new image data for the binary mask
      const newImgData = tempCtx.createImageData(width, height);
      const newData = newImgData.data;

      // Loop through pixels: if alpha > 0, make it white; otherwise black
      for (let i = 0; i < data.length; i += 4) {
        const alpha = data[i + 3];
        if (alpha > 0) {
          // White (Selected)
          newData[i] = 255;     // R
          newData[i + 1] = 255; // G
          newData[i + 2] = 255; // B
          newData[i + 3] = 255; // A
        } else {
          // Black (Background)
          newData[i] = 0;
          newData[i + 1] = 0;
          newData[i + 2] = 0;
          newData[i + 3] = 255;
        }
      }

      tempCtx.putImageData(newImgData, 0, 0);
      return tempCanvas.toDataURL('image/png');
    }
  }));

  // Initialize and resize canvases
  useEffect(() => {
    if (!image || !containerRef.current || !imageCanvasRef.current || !maskCanvasRef.current) return;

    const container = containerRef.current;
    const imageCanvas = imageCanvasRef.current;
    const maskCanvas = maskCanvasRef.current;

    // Calculate aspect ratio fit
    const maxWidth = container.clientWidth;
    const maxHeight = container.clientHeight;
    const imgRatio = image.width / image.height;
    const containerRatio = maxWidth / maxHeight;

    let displayWidth, displayHeight;

    if (containerRatio > imgRatio) {
      displayHeight = maxHeight;
      displayWidth = displayHeight * imgRatio;
    } else {
      displayWidth = maxWidth;
      displayHeight = displayWidth / imgRatio;
    }

    // Set canvas dimensions to match display size for crisp rendering
    // Ideally we match natural size but for performance/display we scale
    // Let's use natural size for the buffer, style width for display
    imageCanvas.width = image.width;
    imageCanvas.height = image.height;
    maskCanvas.width = image.width;
    maskCanvas.height = image.height;

    // Draw the main image
    const ctx = imageCanvas.getContext('2d');
    if (ctx) {
      ctx.drawImage(image, 0, 0);
    }

    // Set CSS dimensions
    setScale(displayWidth / image.width);

  }, [image]);

  // Handle Drawing Logic
  const getCoordinates = (e: React.MouseEvent<HTMLCanvasElement>): Point | null => {
    if (!maskCanvasRef.current || !image) return null;
    const rect = maskCanvasRef.current.getBoundingClientRect();
    const x = (e.clientX - rect.left) / scale;
    const y = (e.clientY - rect.top) / scale;
    return { x, y };
  };

  const draw = useCallback((e: React.MouseEvent<HTMLCanvasElement>) => {
    if (!isDrawing || !maskCanvasRef.current) return;

    const point = getCoordinates(e);
    if (!point) return;

    const ctx = maskCanvasRef.current.getContext('2d');
    if (!ctx) return;

    ctx.lineJoin = 'round';
    ctx.lineCap = 'round';
    ctx.lineWidth = brushSize / scale; // Adjust brush size for scale

    if (tool === ToolType.ERASER) {
      ctx.globalCompositeOperation = 'destination-out';
    } else {
      ctx.globalCompositeOperation = 'source-over';
      ctx.strokeStyle = 'rgba(255, 50, 50, 0.5)'; // Red semi-transparent mask
      ctx.fillStyle = 'rgba(255, 50, 50, 0.5)';
    }

    ctx.beginPath();
    if (lastPoint) {
      ctx.moveTo(lastPoint.x, lastPoint.y);
      ctx.lineTo(point.x, point.y);
      ctx.stroke();
    } else {
        // Dot
        ctx.arc(point.x, point.y, ctx.lineWidth / 2, 0, Math.PI * 2);
        ctx.fill();
    }

    setLastPoint(point);
    onMaskChange(true); // Signal that mask has been modified
  }, [isDrawing, lastPoint, tool, brushSize, scale, onMaskChange]);

  const handleMouseDown = (e: React.MouseEvent<HTMLCanvasElement>) => {
    if (tool === ToolType.MOVE) return;
    setIsDrawing(true);
    const point = getCoordinates(e);
    setLastPoint(point);
    draw(e); // Draw initial dot
  };

  const handleMouseUp = () => {
    setIsDrawing(false);
    setLastPoint(null);
  };

  const handleMouseEnter = () => {
    if (cursorRef.current) cursorRef.current.style.display = 'block';
  };

  const handleMouseLeave = () => {
    if (cursorRef.current) cursorRef.current.style.display = 'none';
    setIsDrawing(false);
    setLastPoint(null);
  };

  // Custom Cursor for Brush Size
  const handleMouseMove = (e: React.MouseEvent<HTMLCanvasElement>) => {
      if (cursorRef.current) {
          cursorRef.current.style.left = `${e.clientX}px`;
          cursorRef.current.style.top = `${e.clientY}px`;
          cursorRef.current.style.width = `${brushSize}px`;
          cursorRef.current.style.height = `${brushSize}px`;
          cursorRef.current.style.borderColor = tool === ToolType.ERASER ? 'white' : 'red';
      }
      draw(e);
  };

  if (!image) {
    return (
      <div className="flex items-center justify-center h-full text-gray-400 border-2 border-dashed border-gray-700 rounded-xl bg-brand-800/50">
        <div className="text-center p-8">
          <p className="text-xl mb-2">Drag and drop an interior photo</p>
          <p className="text-sm text-gray-500">or upload from the sidebar</p>
        </div>
      </div>
    );
  }

  return (
    <div ref={containerRef} className="relative w-full h-full flex items-center justify-center overflow-hidden bg-brand-900 rounded-xl shadow-inner border border-brand-700">
      <div 
        className="relative shadow-2xl"
        style={{ 
          width: image.width * scale, 
          height: image.height * scale 
        }}
      >
        <canvas
          ref={imageCanvasRef}
          className="absolute top-0 left-0 w-full h-full object-contain"
        />
        <canvas
          ref={maskCanvasRef}
          className={`absolute top-0 left-0 w-full h-full object-contain ${tool === ToolType.MOVE ? 'cursor-grab' : 'cursor-none'}`}
          onMouseDown={handleMouseDown}
          onMouseMove={handleMouseMove}
          onMouseUp={handleMouseUp}
          onMouseLeave={handleMouseLeave}
          onMouseEnter={handleMouseEnter}
        />
      </div>

      {/* Custom Brush Cursor */}
      <div 
        ref={cursorRef}
        className="pointer-events-none fixed border-2 rounded-full transform -translate-x-1/2 -translate-y-1/2 z-50 mix-blend-difference"
        style={{ display: 'none' }}
      />
    </div>
  );
});

