import { GoogleGenAI } from "@google/genai";

// Initialize Gemini Client
// In a real production app, you might proxy this through a backend to keep the key secret,
// but for this client-side demo we use the env var directly as per instructions.
const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

export const generateEditedImage = async (
  imageBase64: string,
  prompt: string,
  maskBase64?: string
): Promise<string> => {
  try {
    // Clean base64 strings
    const cleanImageBase64 = imageBase64.replace(/^data:image\/(png|jpeg|jpg|webp);base64,/, '');
    const cleanMaskBase64 = maskBase64 ? maskBase64.replace(/^data:image\/(png|jpeg|jpg|webp);base64,/, '') : null;

    // We use the high-quality image preview model for professional results
    const model = 'gemini-3-pro-image-preview';

    // Construct a professional system-like prompt to ensure constraints are met
    let fullPrompt = `
    ROLE: Precision Interior Architecture Editor.
    TASK: ${prompt}

    STRICT CONSTRAINTS:
    1. Modify ONLY the requested elements.
    2. Preserve original lighting, shadows, perspective, and camera angle perfectly.
    3. Maintain photorealism and architect-grade accuracy.
    4. Ensure seamless blending of edited areas with the existing environment.
    `;

    if (cleanMaskBase64) {
      fullPrompt += `
      5. A mask image is provided. The WHITE areas in the second image indicate the precise region to edit/remove.
      6. Focus operations strictly on the masked regions.
      `;
    }

    const parts: any[] = [
      { text: fullPrompt },
      {
        inlineData: {
          mimeType: 'image/png',
          data: cleanImageBase64,
        },
      }
    ];

    if (cleanMaskBase64) {
      parts.push({
        inlineData: {
          mimeType: 'image/png',
          data: cleanMaskBase64,
        },
      });
    }

    const response = await ai.models.generateContent({
      model: model,
      contents: {
        parts: parts,
      },
      config: {
        // High quality generation config
        imageConfig: {
            imageSize: '1K',
            aspectRatio: '1:1'
        }
      }
    });

    // Extract image from response
    // The response candidates content parts will contain the image
    const contentParts = response.candidates?.[0]?.content?.parts;

    if (!contentParts) {
      throw new Error("No content generated");
    }

    // Find the image part
    const imagePart = contentParts.find(p => p.inlineData);

    if (imagePart && imagePart.inlineData && imagePart.inlineData.data) {
       return `data:image/png;base64,${imagePart.inlineData.data}`;
    }

    throw new Error("No image data found in response");

  } catch (error) {
    console.error("Gemini API Error:", error);
    throw error;
  }
};

