import { GoogleGenAI } from "@google/genai";

// Helper to parse base64 data and extract mime type
const parseBase64 = (base64Data: string) => {
  const match = base64Data.match(/^data:(image\/\w+);base64,(.+)$/);
  if (match) {
    return { mimeType: match[1], data: match[2] };
  }
  // Fallback if no header is present, though typical FileReader output has it.
  // Defaulting to png if unknown is risky but better than nothing.
  return { mimeType: 'image/png', data: base64Data.replace(/^data:image\/\w+;base64,/, '') };
};

export const generateEditedImage = async (
  imageBase64: string,
  prompt: string,
  maskBase64?: string
): Promise<string> => {
  try {
    // Initialize Gemini Client dynamically to pick up any key changes
    const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

    const imageObj = parseBase64(imageBase64);
    const maskObj = maskBase64 ? parseBase64(maskBase64) : null;

    // We use the high-quality image preview model for professional results
    const model = 'gemini-3-pro-image-preview';

    // Construct a professional system-like prompt to ensure constraints are met
    let fullPrompt = `
    ROLE: Precision Interior Architecture Editor.
    TASK: ${prompt}

    STRICT CONSTRAINTS:
    1. Modify ONLY the requested elements.
    2. Preserve original lighting, shadows, perspective, and camera angle perfectly.
    3. Maintain photorealism and architect-grade accuracy.
    4. Ensure seamless blending of edited areas with the existing environment.
    `;

    if (maskObj) {
      fullPrompt += `
      5. A mask image is provided. The WHITE areas in the second image indicate the precise region to edit/remove.
      6. Focus operations strictly on the masked regions.
      `;
    }

    const parts: any[] = [
      { text: fullPrompt },
      {
        inlineData: {
          mimeType: imageObj.mimeType,
          data: imageObj.data,
        },
      }
    ];

    if (maskObj) {
      parts.push({
        inlineData: {
          mimeType: maskObj.mimeType,
          data: maskObj.data,
        },
      });
    }

    const response = await ai.models.generateContent({
      model: model,
      contents: {
        parts: parts,
      },
      config: {
        // High quality generation config
        imageConfig: {
            imageSize: '1K',
            aspectRatio: '1:1'
        }
      }
    });

    // Extract image from response
    // The response candidates content parts will contain the image
    const contentParts = response.candidates?.[0]?.content?.parts;

    if (!contentParts) {
      throw new Error("No content generated");
    }

    // Find the image part
    const imagePart = contentParts.find(p => p.inlineData);

    if (imagePart && imagePart.inlineData && imagePart.inlineData.data) {
       return `data:image/png;base64,${imagePart.inlineData.data}`;
    }

    throw new Error("No image data found in response");

  } catch (error) {
    console.error("Gemini API Error:", error);
    throw error;
  }
};

export const generateInteriorVideo = async (
  imageBase64: string,
  prompt: string
): Promise<string> => {
  try {
    // Initialize Gemini Client dynamically
    // IMPORTANT: Users must select their own paid API key for Veo models.
    const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

    const imageObj = parseBase64(imageBase64);

    let operation = await ai.models.generateVideos({
      model: 'veo-3.1-fast-generate-preview',
      prompt: prompt || "Cinematic slow pan of the interior design, 4k, high resolution, architectural visualization",
      image: {
        imageBytes: imageObj.data,
        mimeType: imageObj.mimeType,
      },
      config: {
        numberOfVideos: 1,
        resolution: '720p',
        aspectRatio: '16:9'
      }
    });

    // Poll for completion
    while (!operation.done) {
      await new Promise(resolve => setTimeout(resolve, 5000)); // Check every 5s
      operation = await ai.operations.getVideosOperation({operation: operation});
    }

    if (operation.error) {
        throw new Error(`Video generation failed: ${operation.error.message || 'Unknown error'}`);
    }

    const videoUri = operation.response?.generatedVideos?.[0]?.video?.uri;

    if (!videoUri) {
      throw new Error("Video generation completed but no URI returned. This might be due to safety filters.");
    }

    // Fetch the actual video bytes using the key
    const response = await fetch(`${videoUri}&key=${process.env.API_KEY}`);
    if (!response.ok) {
      throw new Error("Failed to download generated video.");
    }

    const blob = await response.blob();
    return URL.createObjectURL(blob);

  } catch (error) {
    console.error("Gemini Video API Error:", error);
    throw error;
  }
};

import { GoogleGenAI } from "@google/genai";

// Helper to parse base64 data and extract mime type
const parseBase64 = (base64Data: string) => {
  const match = base64Data.match(/^data:(image\/\w+);base64,(.+)$/);
  if (match) {
    return { mimeType: match[1], data: match[2] };
  }
  return { mimeType: 'image/png', data: base64Data.replace(/^data:image\/\w+;base64,/, '') };
};

// Helper to resize image for video generation to avoid payload limits and detect orientation
const processImageForVideo = async (base64: string): Promise<{ data: string, mimeType: string, isPortrait: boolean }> => {
  return new Promise((resolve, reject) => {
    const img = new Image();
    img.crossOrigin = "Anonymous"; // Handle potential CORS if loaded from external source, though here it's base64
    img.onload = () => {
      let width = img.width;
      let height = img.height;
      const isPortrait = height > width;

      // Resize if dimensions exceed 1280px to ensure stability with Veo
      const MAX_DIM = 1280;
      if (width > MAX_DIM || height > MAX_DIM) {
        if (width > height) {
          height = Math.round((height * MAX_DIM) / width);
          width = MAX_DIM;
        } else {
          width = Math.round((width * MAX_DIM) / height);
          height = MAX_DIM;
        }
      }

      const canvas = document.createElement('canvas');
      canvas.width = width;
      canvas.height = height;
      const ctx = canvas.getContext('2d');
      if (!ctx) {
        reject(new Error("Failed to get canvas context"));
        return;
      }

      // Draw white background to handle transparent PNGs correctly
      ctx.fillStyle = '#FFFFFF';
      ctx.fillRect(0, 0, width, height);
      ctx.drawImage(img, 0, 0, width, height);

      // Export as JPEG for best compatibility with video models
      const newDataUrl = canvas.toDataURL('image/jpeg', 0.9);
      const data = newDataUrl.replace(/^data:image\/jpeg;base64,/, '');

      resolve({ data, mimeType: 'image/jpeg', isPortrait });
    };
    img.onerror = (e) => reject(new Error("Failed to load image for processing"));
    img.src = base64;
  });
};

